1	import { getServerSession } from "next-auth";
2	import { authOptions } from "@/lib/auth";
3	import { redirect } from "next/navigation";
4	import Sidebar from "@/components/Sidebar";
5	import Header from "@/components/Header";
6	import styles from "./dashboard-layout.module.css";
7	import poolPromise from "@/lib/db";
8	
9	// Admin yetkisi olan kullanıcı ID'leri (Oğuzhan Eker: 2, Selin Eker: 1)
10	const ADMIN_USER_IDS = new Set(["1", "2"]);
11	
12	export default async function DashboardLayout({
13	  children,
14	}: {
15	  children: React.ReactNode;
16	}) {
17	  const session = await getServerSession(authOptions);
18	  if (!session) redirect("/login");
19	
20	  const userId  = (session.user as any)?.userId as string | undefined;
21	  const isAdmin = userId ? ADMIN_USER_IDS.has(userId) : false;
22	
23	  // Kullanıcının yetkili menü key'lerini DB'den çek
24	  let allowedKeys: string[] = [];
25	  try {
26	    const pool   = await poolPromise;
27	    const result = await pool.request()
28	      .input("userId", userId ? parseInt(userId) : 0)
29	      .query("SELECT MenuKey FROM PortalYetki WHERE KullaniciID = @userId");
30	    allowedKeys = result.recordset.map((r: any) => r.MenuKey as string);
31	  } catch {
32	    // DB hatası → tüm menüler açık kalsın
33	    allowedKeys = [];
34	  }
35	
36	  return (
37	    <div className={styles.shell}>
38	      <Sidebar allowedKeys={allowedKeys} isAdmin={isAdmin} />
39	      <div className={styles.main}>
40	        <Header />
41	        <div className={styles.content}>{children}</div>
42	      </div>
43	    </div>
44	  );
45	}
