1	"use client";
2	
3	import { useState, useEffect, useCallback, useRef } from "react";
4	import styles from '@/app/styles/table.module.css';
5	// ----------------------------------------------------------------
6	// Types
7	// ----------------------------------------------------------------
8	interface Musteri {
9	  ID: number;
10	  Ad: string;
11	  Adres: string | null;
12	  VergiDairesi: string | null;
13	  VergiNo: string | null;
14	  Telefon: string | null;
15	  Email: string | null;
16	  Web: string | null;
17	  Tur2: string | null;
18	  Yetkili: string | null;
19	  Kimin: string | null;
20	}
21	
22	interface ApiResponse {
23	  data: Musteri[];
24	  total: number;
25	  page: number;
26	  limit: number;
27	  totalPages: number;
28	}
29	
30	const emptyForm: Omit<Musteri, "ID" | "Kimin"> = {
31	  Ad: "", Adres: "", VergiDairesi: "", VergiNo: "",
32	  Telefon: "", Email: "", Web: "", Tur2: "Müşteri", Yetkili: "",
33	};
34	
35	const PAGE_SIZE_OPTIONS = [10, 20, 50];
36	
37	// ----------------------------------------------------------------
38	// Main Component
39	// ----------------------------------------------------------------
40	export default function MusteriTable() {
41	  const [data, setData] = useState<Musteri[]>([]);
42	  const [total, setTotal] = useState(0);
43	  const [totalPages, setTotalPages] = useState(1);
44	  const [loading, setLoading] = useState(true);
45	  const [error, setError] = useState("");
46	
47	  const [search, setSearch] = useState("");
48	  const [page, setPage] = useState(1);
49	  const [limit, setLimit] = useState(20);
50	
51	  const [modalOpen, setModalOpen] = useState(false);
52	  const [modalMode, setModalMode] = useState<"add" | "edit">("add");
53	  const [form, setForm] = useState<Omit<Musteri, "ID" | "Kimin">>(emptyForm);
54	  const [editId, setEditId] = useState<number | null>(null);
55	  const [saving, setSaving] = useState(false);
56	  const [formError, setFormError] = useState("");
57	
58	  const [deleteTarget, setDeleteTarget] = useState<Musteri | null>(null);
59	  const [deleting, setDeleting] = useState(false);
60	
61	  const searchTimeout = useRef<ReturnType<typeof setTimeout> | null>(null);
62	
63	  const fetchData = useCallback(async (s: string, p: number, l: number) => {
64	    setLoading(true);
65	    setError("");
66	    try {
67	      const params = new URLSearchParams({ search: s, page: String(p), limit: String(l) });
68	      const res = await fetch(`/api/musteriler?${params}`);
69	      if (!res.ok) throw new Error((await res.json()).error || "Veri alınamadı");
70	      const json: ApiResponse = await res.json();
71	      setData(json.data);
72	      setTotal(json.total);
73	      setTotalPages(json.totalPages);
74	    } catch (e: any) {
75	      setError(e.message);
76	    } finally {
77	      setLoading(false);
78	    }
79	  }, []);
80	
81	  useEffect(() => { fetchData(search, page, limit); }, [page, limit, fetchData, search]);
82	
83	  const handleSearch = (val: string) => {
84	    setSearch(val);
85	    if (searchTimeout.current) clearTimeout(searchTimeout.current);
86	    searchTimeout.current = setTimeout(() => {
87	      setPage(1);
88	      fetchData(val, 1, limit);
89	    }, 350);
90	  };
91	
92	  const openAdd = () => {
93	    setForm(emptyForm);
94	    setEditId(null);
95	    setFormError("");
96	    setModalMode("add");
97	    setModalOpen(true);
98	  };
99	
100	  const openEdit = (m: Musteri) => {
101	    setForm({
102	      Ad: m.Ad || "", Adres: m.Adres || "", VergiDairesi: m.VergiDairesi || "",
103	      VergiNo: m.VergiNo || "", Telefon: m.Telefon || "", Email: m.Email || "",
104	      Web: m.Web || "", Tur2: m.Tur2 || "Müşteri", Yetkili: m.Yetkili || "",
105	    });
106	    setEditId(m.ID);
107	    setFormError("");
108	    setModalMode("edit");
109	    setModalOpen(true);
110	  };
111	
112	  const handleFormChange = (field: keyof typeof form, value: string) => {
113	    setForm(prev => ({ ...prev, [field]: value }));
114	  };
115	
116	  const handleSave = async () => {
117	    if (!form.Ad.trim()) { setFormError("Firma adı zorunludur."); return; }
118	    setSaving(true);
119	    setFormError("");
120	    try {
121	      const url = modalMode === "edit" ? `/api/musteriler/${editId}` : "/api/musteriler";
122	      const method = modalMode === "edit" ? "PUT" : "POST";
123	      const res = await fetch(url, {
124	        method, headers: { "Content-Type": "application/json" }, body: JSON.stringify(form),
125	      });
126	      if (!res.ok) throw new Error((await res.json()).error || "İşlem başarısız");
127	      setModalOpen(false);
128	      fetchData(search, page, limit);
129	    } catch (e: any) {
130	      setFormError(e.message);
131	    } finally {
132	      setSaving(false);
133	    }
134	  };
135	
136	  const handleDelete = async () => {
137	    if (!deleteTarget) return;
138	    setDeleting(true);
139	    try {
140	      const res = await fetch(`/api/musteriler/${deleteTarget.ID}`, { method: "DELETE" });
141	      if (!res.ok) throw new Error((await res.json()).error || "İşlem başarısız");
142	      setDeleteTarget(null);
143	      fetchData(search, page, limit);
144	    } catch (e: any) {
145	      alert(e.message);
146	    } finally {
147	      setDeleting(false);
148	    }
149	  };
150	
151	  const pageNumbers = () => {
152	    const pages: (number | "...")[] = [];
153	    if (totalPages <= 7) {
154	      for (let i = 1; i <= totalPages; i++) pages.push(i);
155	    } else {
156	      pages.push(1);
157	      if (page > 3) pages.push("...");
158	      for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) pages.push(i);
159	      if (page < totalPages - 2) pages.push("...");
160	      pages.push(totalPages);
161	    }
162	    return pages;
163	  };
164	
165	  return (
166	    <>
167	      <div className={styles.toolbar}>
168	        <div className={styles.toolbarLeft}>
169	          <div className={styles.searchBox}>
170	            <svg className={styles.searchIcon} viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
171	              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
172	            </svg>
173	            <input
174	              type="text"
175	              placeholder="Firma adı, vergi no, yetkili..."
176	              value={search}
177	              onChange={e => handleSearch(e.target.value)}
178	              className={styles.searchInput}
179	            />
180	            {search && (
181	              <button className={styles.searchClear} onClick={() => handleSearch("")}>
182	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
183	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
184	                </svg>
185	              </button>
186	            )}
187	          </div>
188	        </div>
189	
190	        <div className={styles.toolbarRight}>
191	          <span className={styles.totalCount}>{total} kayıt</span>
192	          <select
193	            className={styles.pageSizeSelect}
194	            value={limit}
195	            onChange={e => { setLimit(Number(e.target.value)); setPage(1); }}
196	          >
197	            {PAGE_SIZE_OPTIONS.map(n => <option key={n} value={n}>{n} / sayfa</option>)}
198	          </select>
199	          <button className={styles.addBtn} onClick={openAdd}>
200	            <svg viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
201	              <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
202	            </svg>
203	            Yeni Firma
204	          </button>
205	        </div>
206	      </div>
207	
208	      <div className={styles.tableCard}>
209	        {error && <div className={styles.errorBar}>{error}</div>}
210	
211	        <div className={styles.tableWrapper}>
212	          <table className={styles.table}>
213	            <thead>
214	              <tr>
215	                <th>#</th>
216	                <th>Firma Adı</th>
217	                <th>Tür</th>
218	                <th>Adres</th>
219	                <th>V.D. / V.N.</th>
220	                <th>Yetkili</th>
221	                <th>İletişim</th>
222	                <th style={{ width: 90 }}></th>
223	              </tr>
224	            </thead>
225	            <tbody>
226	              {loading ? (
227	                Array.from({ length: 5 }).map((_, i) => (
228	                  <tr key={i}>{Array.from({ length: 8 }).map((__, j) => (
229	                    <td key={j}><div className={styles.skeleton} /></td>
230	                  ))}</tr>
231	                ))
232	              ) : data.length === 0 ? (
233	                <tr>
234	                  <td colSpan={8}>
235	                    <div className={styles.empty}>
236	                      <p>Kayıt bulunamadı.</p>
237	                    </div>
238	                  </td>
239	                </tr>
240	              ) : data.map((m, i) => (
241	                <tr key={m.ID}>
242	                  <td className={styles.tdNum}>{(page - 1) * limit + i + 1}</td>
243	                  <td className={styles.tdName}>{m.Ad || "—"}</td>
244	                  <td>{m.Tur2 || "Müşteri"}</td>
245	                  <td className={styles.tdAdres}>{m.Adres || "—"}</td>
246	                  <td className={styles.tdMono}>
247	                    {m.VergiDairesi ? <div>{m.VergiDairesi}</div> : null}
248	                    {m.VergiNo ? <div style={{ fontSize: '0.8rem', opacity: 0.7 }}>{m.VergiNo}</div> : "—"}
249	                  </td>
250	                  <td>{m.Yetkili || "—"}</td>
251	                  <td>
252	                    <div className={styles.contactCell}>
253	                      {m.Telefon && <span className={styles.contactItem} title="Telefon">📞 {m.Telefon}</span>}
254	                      {m.Email && (
255	                        <a href={`mailto:${m.Email}`} className={`${styles.contactItem} ${styles.emailLink}`} title="E-posta">
256	                          ✉️ {m.Email}
257	                        </a>
258	                      )}
259	                      {m.Web && (
260	                        <a href={m.Web.startsWith("http") ? m.Web : `https://${m.Web}`}
261	                          target="_blank" rel="noopener noreferrer"
262	                          className={`${styles.contactItem} ${styles.webLink}`} title="Web Sitesi">
263	                          🌐 {m.Web}
264	                        </a>
265	                      )}
266	                    </div>
267	                  </td>
268	                  <td>
269	                    <div className={styles.actionBtns}>
270	                      <button className={styles.editBtn} onClick={() => openEdit(m)} title="Düzenle">
271	                        <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
272	                          <path d="m5.433 13.917 1.262-3.155A4 4 0 0 1 7.58 9.42l6.92-6.918a2.121 2.121 0 0 1 3 3l-6.92 6.918c-.383.383-.84.685-1.343.886l-3.154 1.262a.5.5 0 0 1-.65-.65Z" />
273	                        </svg>
274	                      </button>
