341	              <button className={styles.cancelBtn} onClick={() => setModalOpen(false)}>İptal</button>
342	              <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>{saving ? "..." : "KAYDET"}</button>
343	            </div>
344	          </div>
